$(document).ready(function() {
        // Load statistics
        $.get('/api/products/stats/count', function(data) {
            $('#totalProducts').text(data);
        });
            
        $.get('/api/customers/stats/total', function(data) {
            $('#totalCustomers').text(data);
        });
            
        $.get('/api/orders/stats/total', function(data) {
            $('#totalOrders').text(data);
        });
            
        $.get('/api/promotions/stats/active-count', function(data) {
            $('#activePromotions').text(data);
        });
});